template <typename KeyType>
auto HyperLogLogPresto<KeyType>::AddElem(KeyType val) -> void {
  if (num_buckets_ == 0) {
    return;
  }

  std::lock_guard<std::mutex> guard(mutex_);

  // Hash the value
  hash_t hash_val = CalculateHash(val);

  // Extract bucket index from the first n_leading_bits
  size_t bucket_idx = hash_val & ((1UL << n_leading_bits_) - 1);
  if (n_leading_bits_ == 0) {
    bucket_idx = 0;  // Only one bucket
  }

  // Get the remaining bits after removing the bucket index bits
  hash_t remaining_bits = hash_val >> n_leading_bits_;

  // Count leading zeros in the remaining bits
  uint64_t rho = 1;
  if (remaining_bits != 0) {
    rho = __builtin_clzll(remaining_bits) + 1;
  } else {
    rho = 65;  // All zeros case (64 leading zeros + 1)
  }

  // Store in dense bucket if rho <= DENSE_BUCKET_SIZE (4 bits can store 0-15)
  if (rho <= (1UL << DENSE_BUCKET_SIZE) - 1) {  // 15
    // Update dense bucket with max value
    if (rho > dense_bucket_[bucket_idx].to_ullong()) {
      dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(rho);
    }
  } else {
    // Store in overflow bucket
    if (overflow_bucket_.find(bucket_idx) == overflow_bucket_.end()) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(0);
    }
    // In overflow bucket, we need to track multiple values or just the max
    // Based on the test, it looks like we store the count or additional bits
    auto current = overflow_bucket_[bucket_idx].to_ullong();
    current++;
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(current);
