#include "primer/hyperloglog.h"

namespace bustub {

template <typename KeyType>
HyperLogLog<KeyType>::HyperLogLog(int16_t n_bits)
    : cardinality_(0), n_bits_(n_bits) {
  if (n_bits_ < 0) {
    num_buckets_ = 0;
    registers_.clear();
  } else {
    num_buckets_ = 1UL << n_bits_;  // 2^n_bits, so 2^0=1, 2^1=2, etc.
    registers_.assign(num_buckets_, 0);
  }
}

template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeBinary(const hash_t &hash) const -> std::bitset<BITSET_CAPACITY> {
  return std::bitset<BITSET_CAPACITY>(hash);
}

template <typename KeyType>
auto HyperLogLog<KeyType>::PositionOfLeftmostOne(const std::bitset<BITSET_CAPACITY> &bset) const -> uint64_t {
  // Count leading zeros (from the most significant bit)
  // and return the position of the first 1 bit
  for (int64_t i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;  // Number of leading zeros + 1
    }
  }
  return BITSET_CAPACITY + 1;  // All zeros case
}

template <typename KeyType>
auto HyperLogLog<KeyType>::AddElem(KeyType val) -> void {
  if (num_buckets_ == 0) {
    return;
  }

  std::lock_guard<std::mutex> guard(mutex_);

  // Hash the value
  hash_t hash_val = CalculateHash(val);

  // Extract bucket index from the LSBs (least significant bits)
  size_t bucket_idx = hash_val & ((1UL << n_bits_) - 1);

  // Get the remaining bits after removing the bucket index bits
  hash_t remaining_bits = hash_val >> n_bits_;

  // Convert to bitset and find position of leftmost 1
  auto bset = ComputeBinary(remaining_bits);
  uint64_t rho = PositionOfLeftmostOne(bset);

  // Update the register with the maximum rho value
  if (rho > registers_[bucket_idx]) {
    registers_[bucket_idx] = rho;
  }
