  hash_t hash_val = CalculateHash(val);

  // Extract bucket index from the LSBs (least significant bits)
  size_t bucket_idx = hash_val & ((1UL << n_bits_) - 1);

  // Get the remaining bits after removing the bucket index bits
  hash_t remaining_bits = hash_val >> n_bits_;

  // Find position of leftmost 1 bit (rho value) in remaining_bits
