  // Count leading zeros (from the most significant bit)
  // and return the position of the first 1 bit
  for (int64_t i = BITSET_CAPACITY - 1; i >= 0; i--) {
    if (bset[i]) {
      return BITSET_CAPACITY - i;  // Number of leading zeros + 1
