template <typename KeyType>
auto HyperLogLog<KeyType>::ComputeCardinality() -> void {
  if (num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> guard(mutex_);

  // HyperLogLog formula: E = constant * m^2 / sum(2^(-M[j]))
  // Note: We treat register value 0 as uninitialized (rho = infinity)
  double m = static_cast<double>(num_buckets_);
  double raw_estimate = 0.0;

  for (size_t i = 0; i < num_buckets_; i++) {
    if (registers_[i] == 0) {
      // Uninitialized register (never updated), treat as rho = infinity
      // This means 2^(-infinity) = 0, so we don't add to the sum
      raw_estimate += 0.0;
    } else {
      raw_estimate += std::pow(2.0, -static_cast<double>(registers_[i]));
    }
  }

  // If no registers were set, avoid division by zero
  if (raw_estimate == 0.0) {
    cardinality_ = 0;
    return;
  }

  raw_estimate = CONSTANT * m * m / raw_estimate;

