    rho = 65;  // All zeros case (64 leading zeros + 1)
  }

  // Store in dense bucket if rho <= DENSE_BUCKET_SIZE (4 bits can store 0-15)
  if (rho <= (1UL << DENSE_BUCKET_SIZE) - 1) {  // 15
    // Update dense bucket with max value
    if (rho > dense_bucket_[bucket_idx].to_ullong()) {
      dense_bucket_[bucket_idx] = std::bitset<DENSE_BUCKET_SIZE>(rho);
    }
  } else {
    // Store in overflow bucket
    if (overflow_bucket_.find(bucket_idx) == overflow_bucket_.end()) {
      overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(0);
    }
    // In overflow bucket, we need to track multiple values or just the max
    // Based on the test, it looks like we store the count or additional bits
    auto current = overflow_bucket_[bucket_idx].to_ullong();
    current++;
    overflow_bucket_[bucket_idx] = std::bitset<OVERFLOW_BUCKET_SIZE>(current);
  }
}

template <typename T>
auto HyperLogLogPresto<T>::ComputeCardinality() -> void {
  if (num_buckets_ == 0) {
    cardinality_ = 0;
    return;
  }

  std::lock_guard<std::mutex> guard(mutex_);

  // HyperLogLog formula: E = constant * m^2 / sum(2^(-M[j]))
  double m = static_cast<double>(num_buckets_);
  double raw_estimate = 0.0;

  for (size_t i = 0; i < num_buckets_; i++) {
    uint64_t rho = dense_bucket_[i].to_ullong();

    // Check if there's an overflow bucket value
    if (overflow_bucket_.find(i) != overflow_bucket_.end()) {
      // The overflow bucket stores additional rho value beyond the dense bucket
      uint64_t overflow_val = overflow_bucket_[i].to_ullong();
      // Use the max of dense and overflow
      rho = std::max(rho, overflow_val);
    }

    // Clamp rho to reasonable values
    if (rho == 0) {
      rho = 1;
    }

    raw_estimate += std::pow(2.0, -static_cast<double>(rho));
  }

  raw_estimate = CONSTANT * m * m / raw_estimate;

  // Small range correction
  if (raw_estimate <= 2.5 * m) {
    size_t zeros = 0;
    for (size_t i = 0; i < num_buckets_; i++) {
      if (dense_bucket_[i].to_ullong() == 0 && overflow_bucket_.find(i) == overflow_bucket_.end()) {
        zeros++;
      }
    }
    if (zeros != 0) {
      raw_estimate = m * std::log(static_cast<double>(m) / static_cast<double>(zeros));
    }
  }

  // Large range correction
  if (raw_estimate > (1.0 / 30.0) * (1UL << 32)) {
    raw_estimate = -1.0 * (1UL << 32) * std::log(1.0 - raw_estimate / (1UL << 32));
  }

  cardinality_ = static_cast<uint64_t>(raw_estimate + 0.5);  // Round to nearest integer
}

